import { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";

function AddPlayer() {
  const [formData, setFormData] = useState({
    name: "",
    team: "",
    role: "Batsman",
    matches: "",
    runs: "",
    wickets: "",
    battingAvg: "",
    strikeRate: "",
    bowlingEcon: "",
    highScore: "",
    bestBowling: ""
  });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log("Submitting Player Data:", formData);
    try {
      await API.post("/players", formData);
      alert("Player added successfully!");
      navigate("/players");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to add player");
    }
  };

  return (
    <div className="auth-card" style={{ maxWidth: '600px' }}>
      <h2>Add New Player</h2>
      {error && <p className="error-msg">{error}</p>}
      <form onSubmit={handleSubmit} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
        <div className="input-group" style={{ gridColumn: 'span 2' }}>
          <label>Player Name</label>
          <input type="text" name="name" value={formData.name} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Team</label>
          <input type="text" name="team" value={formData.team} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Role</label>
          <select name="role" value={formData.role} onChange={handleChange} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}>
            <option value="Batsman">Batsman</option>
            <option value="Bowler">Bowler</option>
            <option value="All-rounder">All-rounder</option>
            <option value="Wicketkeeper">Wicketkeeper</option>
          </select>
        </div>
        <div className="input-group">
          <label>Matches</label>
          <input type="number" name="matches" value={formData.matches} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Total Runs</label>
          <input type="number" name="runs" value={formData.runs} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Total Wickets</label>
          <input type="number" name="wickets" value={formData.wickets} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Batting Avg</label>
          <input type="number" step="0.01" name="battingAvg" value={formData.battingAvg} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Strike Rate</label>
          <input type="number" step="0.01" name="strikeRate" value={formData.strikeRate} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Bowling Economy</label>
          <input type="number" step="0.01" name="bowlingEcon" value={formData.bowlingEcon} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>High Score</label>
          <input type="number" name="highScore" value={formData.highScore} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Best Bowling (e.g., 5/20)</label>
          <input type="text" name="bestBowling" value={formData.bestBowling} onChange={handleChange} />
        </div>
        <button type="submit" className="auth-btn" style={{ gridColumn: 'span 2' }}>Save Player</button>
      </form>
    </div>
  );
}

export default AddPlayer;
